#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    if (a < 0) a = -a;
    if (b < 0) b = -b;
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *perm = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &perm[i]);
        int *pos = (int*)malloc((N+1) * sizeof(int));
        for (int i = 0; i < N; ++i) pos[perm[i]] = i+1; // 1‑based
        long long g = 0;
        for (int i = 1; i <= N; ++i) {
            long long diff = (long long)pos[i] - i;
            g = gcd_ll(g, diff);
        }
        if (g < 0) g = -g;
        printf("%lld\n", g);
        free(perm);
        free(pos);
    }
    return 0;
}

